//#region src/config.ts
function defineConfig(config) {
	const plugins = [];
	const layouts = {};
	const adapters = [];
	return {
		$context: void 0,
		get() {
			return {
				...config,
				plugins,
				layouts,
				adapters
			};
		},
		plugins(...plugins) {
			return this.usePlugins(...plugins);
		},
		adapters(...adapters) {
			return this.useAdapters(...adapters);
		},
		layouts(layouts) {
			return this.useLayouts(layouts);
		},
		useAdapters(...values) {
			adapters.push(...values);
			return this;
		},
		useLayouts(overrides) {
			Object.assign(layouts, overrides);
			return this;
		},
		usePlugins(...values) {
			plugins.push(...values);
			return this;
		}
	};
}
//#endregion
export { defineConfig };
